#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_cuda_wrapper.h"

#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

void findK(long height,
           knode *knodes,
           long knodes_elem,
           record *records,
           long *currKnode,
           long *offset,
           int *keys,
           record *ans,
           int count,
           int order)
{
    int threadsPerBlock = order < 1024 ? order : 1024;

    #pragma omp parallel for
    for(int bid = 0; bid < count; bid++) {
        long local_currKnode = currKnode[bid];
        long local_offset = offset[bid];

        int i;
        for(i = 0; i < height; i++){
            int thid;
            for(thid = 0; thid < threadsPerBlock; thid++){
                if((knodes[local_currKnode].keys[thid] <= keys[bid]) && 
                   (knodes[local_currKnode].keys[thid+1] > keys[bid])){
                    if(knodes[local_offset].indices[thid] < knodes_elem){
                        local_offset = knodes[local_offset].indices[thid];
                    }
                }
            }

            local_currKnode = local_offset;
        }

        currKnode[bid] = local_currKnode;
        offset[bid] = local_offset;

        for(int thid = 0; thid < threadsPerBlock; thid++){
            if(knodes[local_currKnode].keys[thid] == keys[bid]){
                ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
                break;
            }
        }
    }
}

void kernel_gpu_cuda_wrapper(record *records,
                             long records_mem,
                             knode *knodes,
                             long knodes_elem,
                             long knodes_mem,
                             int order,
                             long maxheight,
                             int count,
                             long *currKnode,
                             long *offset,
                             int *keys,
                             record *ans)
{
    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long time5;
    long long time6;

    time0 = get_time();

    time1 = get_time();

    int numBlocks;
    numBlocks = count;
    int threadsPerBlock;
    threadsPerBlock = order < 1024 ? order : 1024;

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", numBlocks, threadsPerBlock);

    time2 = get_time();

    time3 = get_time();

    findK(maxheight,
          knodes,
          knodes_elem,
          records,
          currKnode,
          offset,
          keys,
          ans,
          count,
          order);

    time4 = get_time();

    time5 = get_time();

    time6 = get_time();

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

    printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n", (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time6-time0)*100);

    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time6-time0)*100);

    printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n", (float)(time5-time4)/1000000, (float)(time5-time4)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", (float)(time6-time5)/1000000, (float)(time6-time5)/(float)(time6-time0)*100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time6-time0)/1000000);
}

#ifdef __cplusplus
}
#endif

