void findRangeK(long height,
                knode *knodes,
                long knodes_elem,
                long *currKnode,
                long *offset,
                long *lastKnode,
                long *offset_2,
                int *start,
                int *end,
                int *recstart,
                int *reclength,
                int count,
                int order)
{
    int threadsPerBlock = order < 1024 ? order : 1024;

    #pragma omp parallel for
    for(int bid = 0; bid < count; bid++) {
        long local_currKnode = currKnode[bid];
        long local_lastKnode = lastKnode[bid];
        long local_offset = offset[bid];
        long local_offset_2 = offset_2[bid];

        int i;
        for(i = 0; i < height; i++){
            int thid;
            for(thid = 0; thid < threadsPerBlock; thid++){
                if((knodes[local_currKnode].keys[thid] <= start[bid]) && 
                   (knodes[local_currKnode].keys[thid+1] > start[bid])){
                    if(knodes[local_currKnode].indices[thid] < knodes_elem){
                        local_offset = knodes[local_currKnode].indices[thid];
                    }
                }
                if((knodes[local_lastKnode].keys[thid] <= end[bid]) && 
                   (knodes[local_lastKnode].keys[thid+1] > end[bid])){
                    if(knodes[local_lastKnode].indices[thid] < knodes_elem){
                        local_offset_2 = knodes[local_lastKnode].indices[thid];
                    }
                }
            }

            local_currKnode = local_offset;
            local_lastKnode = local_offset_2;
        }

        currKnode[bid] = local_currKnode;
        lastKnode[bid] = local_lastKnode;
        offset[bid] = local_offset;
        offset_2[bid] = local_offset_2;

        for(int thid = 0; thid < threadsPerBlock; thid++){
            if(knodes[local_currKnode].keys[thid] == start[bid]){
                recstart[bid] = knodes[local_currKnode].indices[thid];
                break;
            }
        }

        for(int thid = 0; thid < threadsPerBlock; thid++){
            if(knodes[local_lastKnode].keys[thid] == end[bid]){
                reclength[bid] = knodes[local_lastKnode].indices[thid] - recstart[bid] + 1;
                break;
            }
        }
    }
}

